+use chrono::{Duration, Utc};
+use fcp_core::{
+    CapabilityId, CapabilityToken, FcpConnector, FcpError, HandshakeRequest, InvokeRequest,
+    OperationId, RequestId, SelfCheckStatus, ZoneId,
+};
+use fcp_crypto::{cose::CapabilityTokenBuilder, ed25519::Ed25519SigningKey};
+use fcp_synology_chat::SynologyChatConnector;
+use serde_json::{Value, json};
+use wiremock::{
+    Mock, MockServer, ResponseTemplate,
+    matchers::{body_json, method, path},
+};
+
+const CAP_READ: &str = "synology_chat.read";
+const CAP_WRITE: &str = "synology_chat.write";
+
+const OP_SEND_MESSAGE: &str = "synology_chat.send_message";
+const OP_SEND_PAYLOAD: &str = "synology_chat.send_payload";
+const OP_HEALTH: &str = "synology_chat.health";
+
+fn handshake_request(host_public_key: [u8; 32], capabilities: &[&str]) -> HandshakeRequest {
+    HandshakeRequest {
+        protocol_version: "2.0.0".into(),
+        zone: ZoneId::work(),
+        zone_dir: None,
+        host_public_key,
+        nonce: [11u8; 32],
+        capabilities_requested: capabilities
+            .iter()
+            .map(|capability| CapabilityId::new(*capability).expect("capability id"))
+            .collect(),
+        host: None,
+        transport_caps: None,
+        requested_instance_id: None,
+    }
+}
+
+fn capability_token(
+    signing_key: &Ed25519SigningKey,
+    capability: &str,
+    operations: &[&str],
+) -> CapabilityToken {
+    let now = Utc::now();
+    let raw = CapabilityTokenBuilder::new()
+        .capability_id(capability)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(operations)
+        .issuer("node:test")
+        .validity(now, now + Duration::hours(1))
+        .sign(signing_key)
+        .expect("token should sign");
+    CapabilityToken { raw }
+}
+
+fn invoke_request(
+    connector: &SynologyChatConnector,
+    operation: &'static str,
+    input: Value,
+    capability_token: CapabilityToken,
+) -> InvokeRequest {
+    InvokeRequest {
+        r#type: "invoke".into(),
+        id: RequestId::new("synology-chat-integration"),
+        connector_id: connector.id().clone(),
+        operation: OperationId::from_static(operation),
+        zone_id: ZoneId::work(),
+        input,
+        capability_token,
+        holder_proof: None,
+        context: None,
+        idempotency_key: None,
+        lease_seq: None,
+        deadline_ms: None,
+        correlation_id: None,
+        provenance: None,
+        approval_tokens: Vec::new(),
+    }
+}
+
+async fn setup_connector(
+    incoming_url: &str,
+    capabilities: &[&str],
+) -> (SynologyChatConnector, Ed25519SigningKey) {
+    let mut connector = SynologyChatConnector::new();
+    connector
+        .configure(json!({
+            "incoming_url": incoming_url,
+            "request_timeout_ms": 2_000
+        }))
+        .await
+        .expect("configure should succeed");
+    let signing_key = Ed25519SigningKey::generate();
+    connector
+        .handshake(handshake_request(
+            signing_key.verifying_key().to_bytes(),
+            capabilities,
+        ))
+        .await
+        .expect("handshake should succeed");
+    (connector, signing_key)
+}
+
+async fn invoke_ok(
+    connector: &SynologyChatConnector,
+    operation: &'static str,
+    input: Value,
+    capability: &str,
+    signing_key: &Ed25519SigningKey,
+) -> Value {
+    connector
+        .invoke(invoke_request(
+            connector,
+            operation,
+            input,
+            capability_token(signing_key, capability, &[operation]),
+        ))
+        .await
+        .expect("invoke should succeed")
+        .result
+        .expect("successful invoke should carry a result")
+}
